     1→#!/usr/bin/env nu
     2→# Test real adapters (claude, ollama, codex) end-to-end through the dispatcher pipeline.
     3→#
     4→# Usage:
     5→#   nu --no-config-file scripts/test-real-adapters.nu [--adapter <name>] [--timeout <seconds>] [--test]
     6→#
     7→# Flags:
     8→#   --adapter <name>   Adapter to test (default: all). Options: all, claude, ollama, codex
     9→#   --timeout <seconds> Timeout in seconds for each adapter test (default: 120)
    10→#   --test             Run internal self-tests
    11→#   --help             Show this help message
    12→
    13→def main [
    14→  --adapter: string = "all"  # Adapter to test (all, claude, ollama, codex)
    15→  --timeout: int = 120       # Timeout in seconds
    16→  --test                      # Run internal self-tests
    17→  --help                      # Show help message
    18→] {
    19→  if $help {
    20→    print "Test real adapters (claude, ollama, codex) end-to-end through the dispatcher pipeline."
    21→    print ""
    22→    print "Usage:"
    23→    print "  nu --no-config-file scripts/test-real-adapters.nu [OPTIONS]"
    24→    print ""
    25→    print "Options:"
    26→    print "  --adapter <name>     Adapter to test (default: all)"
    27→    print "                       Options: all, claude, ollama, codex"
    28→    print "  --timeout <seconds>  Timeout in seconds for each test (default: 120)"
    29→    print "  --test               Run internal self-tests"
    30→    print "  --help               Show this help message"
    31→    print ""
    32→    print "Examples:"
    33→    print "  nu --no-config-file scripts/test-real-adapters.nu"
    34→    print "  nu --no-config-file scripts/test-real-adapters.nu --adapter claude"
    35→    print "  nu --no-config-file scripts/test-real-adapters.nu --adapter ollama --timeout 60"
    36→    print "  nu --no-config-file scripts/test-real-adapters.nu --test"
    37→    return
    38→  }
    39→
    40→  if $test {
    41→    run_tests
    42→    return
    43→  }
    44→
    45→  # Build bop binary before running tests
    46→  print "Building bop binary..."
    47→  build_bop
    48→  let bop = (get_bop_bin)
    49→  if not ($bop | path exists) {
    50→    print "ERROR: bop binary not found after build"
    51→    exit 1
    52→  }
    53→
    54→  # Determine which adapters to test
    55→  let adapters_to_test = if $adapter == "all" {
    56→    ["claude", "ollama", "codex"]
    57→  } else {
    58→    [$adapter]
    59→  }
    60→
    61→  # Track results
    62→  mut results = []
    63→  mut all_passed = true
    64→
    65→  # Test each adapter
    66→  for adapter_name in $adapters_to_test {
    67→    # Check if adapter script exists
    68→    let adapter_path = (get_adapter_path $adapter_name)
    69→    if not ($adapter_path | path exists) {
    70→      let result = {adapter: $adapter_name, success: false, reason: "adapter script not found"}
    71→      $results = ($results | append [$result])
    72→      $all_passed = false
    73→      continue
    74→    }
    75→
    76→    # Run adapter test
    77→    let test_result = (run_adapter_test $adapter_name $timeout)
    78→    $results = ($results | append [$test_result])
    79→
    80→    if not $test_result.success {
    81→      $all_passed = false
    82→    }
    83→  }
    84→
    85→  # Format and display results
    86→  print ""
    87→  print "Test Results:"
    88→  print "============="
    89→  for result in $results {
    90→    let symbol = if $result.success { "✓" } else { "⊘" }
    91→    let status = if $result.success { "PASS" } else { "FAIL" }
    92→    print $"($symbol) ($result.adapter): ($status)"
    93→    if not $result.success and "reason" in $result {
    94→      print $"  Reason: ($result.reason)"
    95→    }
    96→  }
    97→
    98→  # Exit with appropriate code
    99→  if not $all_passed {
   100→    exit 1
   101→  }
   102→}
   103→
   104→# Run a single adapter test
   105→def run_adapter_test [
   106→  adapter: string  # Adapter name to test
   107→  timeout_sec: int # Timeout in seconds
   108→]: nothing -> record<adapter: string, success: bool, reason: string> {
   109→  let card_id = $"test-($adapter)-(date now | format date '%s')"
   110→
   111→  # Create test setup
   112→  let setup = try {
   113→    create_test_setup $adapter
   114→  } catch { |err|
   115→    return {adapter: $adapter, success: false, reason: $"setup failed: ($err.msg)"}
   116→  }
   117→
   118→  # Write template
   119→  try {
   120→    write_template $setup.cards_dir "implement"
   121→  } catch { |err|
   122→    cleanup_test_setup $setup.temp_dir
   123→    return {adapter: $adapter, success: false, reason: $"write template failed: ($err.msg)"}
   124→  }
   125→
   126→  # Create test card
   127→  try {
   128→    create_test_card $setup.cards_dir "implement" $card_id
   129→  } catch { |err|
   130→    cleanup_test_setup $setup.temp_dir
   131→    return {adapter: $adapter, success: false, reason: $"create card failed: ($err.msg)"}
   132→  }
   133→
   134→  # Start dispatcher
   135→  let log_file = ($setup.temp_dir | path join "dispatcher.log")
   136→  start_dispatcher $setup.cards_dir $adapter $log_file
   137→
   138→  # Give dispatcher a moment to start
   139→  sleep 500ms
   140→
   141→  # Wait for card completion
   142→  let completion = (wait_for_card_completion $setup.cards_dir $card_id $timeout_sec)
   143→
   144→  # Stop dispatcher
   145→  stop_dispatcher $setup.cards_dir
   146→
   147→  # Check results
   148→  let result = if not $completion.success {
   149→    {adapter: $adapter, success: false, reason: $"card stuck in ($completion.state) state"}
   150→  } else {
   151→    let assertion = (assert_result $setup.cards_dir $card_id)
   152→    if $assertion.success {
   153→      {adapter: $adapter, success: true, reason: "test passed"}
   154→    } else {
   155→      {adapter: $adapter, success: false, reason: $assertion.message}
   156→    }
   157→  }
   158→
   159→  # Cleanup (keep temp dir on failure for debugging)
   160→  if not $result.success {
   161→    print $"DEBUG: temp_dir kept at: ($setup.temp_dir)"
   162→  } else {
   163→    cleanup_test_setup $setup.temp_dir
   164→  }
   165→
   166→  $result
   167→}
   168→
   169→# Check if a specific adapter command is available in PATH
   170→def is_adapter_available [
   171→  adapter: string  # Adapter name (claude, ollama, or codex)
   172→]: nothing -> bool {
   173→  # Check if command exists
   174→  let cmd_result = (do { ^which $adapter } | complete)
   175→  if $cmd_result.exit_code != 0 {
   176→    return false
   177→  }
   178→
   179→  # Additional checks per adapter
   180→  if $adapter == "ollama" {
   181→    # Check if ollama server is running
   182→    let server_result = (do { ^curl -sf http://localhost:11434/api/tags } | complete)
   183→    return ($server_result.exit_code == 0)
   184→  } else if $adapter == "codex" {
   185→    # Check if OPENAI_API_KEY is set
   186→    return ("OPENAI_API_KEY" in $env)
   187→  } else {
   188→    # claude or other adapters: just check command existence
   189→    return true
   190→  }
   191→}
   192→
   193→# Get list of available adapters from the standard set
   194→def get_available_adapters []: nothing -> list<string> {
   195→  ["claude", "ollama", "codex"]
   196→  | where { |adapter| (is_adapter_available $adapter) }
   197→}
   198→
   199→# Get path to the bop binary
   200→def get_bop_bin []: nothing -> path {
   201→  let root = ($env.CURRENT_FILE | path dirname | path dirname)
   202→  $root | path join "target" "debug" "bop"
   203→}
   204→
   205→# Get path to the repository root
   206→def get_repo_root []: nothing -> path {
   207→  $env.CURRENT_FILE | path dirname | path dirname
   208→}
   209→
   210→# Get path to an adapter script
   211→def get_adapter_path [
   212→  adapter: string  # Adapter name (e.g., "mock", "claude", "ollama")
   213→]: nothing -> path {
   214→  let root = (get_repo_root)
   215→  $root | path join "adapters" $"($adapter).nu"
   216→}
   217→
   218→# Build the bop binary before running tests
   219→def build_bop []: nothing -> nothing {
   220→  let root = (get_repo_root)
   221→  let result = (do {
   222→    cargo build
   223→  } | complete)
   224→
   225→  if $result.exit_code != 0 {
   226→    error make {
   227→      msg: "Failed to build bop binary"
   228→      label: {
   229→        text: $"cargo build failed with exit code ($result.exit_code)"
   230→        span: (metadata $result).span
   231→      }
   232→    }
   233→  }
   234→}
   235→
   236→# Create a test setup with temp directory, .cards structure, and providers.json
   237→def create_test_setup [
   238→  adapter: string  # Primary adapter to use (e.g., "mock", "claude")
   239→]: nothing -> record<cards_dir: path, temp_dir: path> {
   240→  # Create temp directory
   241→  let temp_dir = (mktemp -d)
   242→  let cards_dir = ($temp_dir | path join ".cards")
   243→
   244→  # Initialize .cards directory
   245→  let bop = (get_bop_bin)
   246→  let init_result = (do {
   247→    ^$bop --cards-dir $cards_dir init
   248→  } | complete)
   249→
   250→  if $init_result.exit_code != 0 {
   251→    error make {
   252→      msg: "Failed to initialize .cards directory"
   253→      label: {
   254→        text: $"bop init failed with exit code ($init_result.exit_code)"
   255→        span: (metadata $init_result).span
   256→      }
   257→    }
   258→  }
   259→
   260→  # Write providers.json
   261→  write_providers $cards_dir $adapter
   262→
   263→  {cards_dir: $cards_dir, temp_dir: $temp_dir}
   264→}
   265→
   266→# Write providers.json with the specified adapter
   267→def write_providers [
   268→  cards_dir: path   # Path to .cards directory
   269→  adapter: string   # Adapter name (e.g., "mock", "claude")
   270→]: nothing -> nothing {
   271→  let adapter_path = (get_adapter_path $adapter)
   272→  let adapter_str = ($adapter_path | str replace --all '\\' '\\\\')
   273→
   274→  let providers = {
   275→    providers: {
   276→      $adapter: {
   277→        command: $adapter_str
   278→        rate_limit_exit: 75
   279→      }


